import redis
from rediscluster import RedisCluster

# Set up a list of node IPs
startup_nodes = [{"host": "127.0.0.1", "port": "7000"}, 
                 {"host": "127.0.0.1", "port": "7001"}]

# Create a Redis Cluster instance
rc = RedisCluster(startup_nodes=startup_nodes, decode_responses=True)

# Function to cache session tokens and API keys with a TTL
def cache_user_data(user_id: str, session_token: str, api_key: str, ttl: int):
    pipeline = rc.pipeline()

    # Store session token and API key with TTL
    pipeline.setex(f"{user_id}:session_token", ttl, session_token)
    pipeline.setex(f"{user_id}:api_key", ttl, api_key)

    # Execute the pipeline
    pipeline.execute()

# Function to retrieve session tokens and API keys from the cache
def retrieve_user_data(user_id: str):
    pipeline = rc.pipeline()

    # Retrieve session token and API key
    pipeline.get(f"{user_id}:session_token")
    pipeline.get(f"{user_id}:api_key")

    # Execute the pipeline and return the results
    return pipeline.execute()